import json

lines = open('ios_crash.ips').readlines()
crash = json.loads(''.join(lines[1:]))

# Look for more detail - check for any managed exception info
# Check all top-level keys
print('=== Top-level keys ===')
for k in crash.keys():
    v = crash[k]
    if isinstance(v, str) and len(v) < 200:
        print(f'  {k}: {v}')
    elif isinstance(v, (int, float, bool)):
        print(f'  {k}: {v}')
    elif isinstance(v, dict):
        print(f'  {k}: (dict, {len(v)} keys)')
    elif isinstance(v, list):
        print(f'  {k}: (list, {len(v)} items)')
    else:
        print(f'  {k}: {type(v).__name__}')

# Check if there are any trial/crashed thread reason fields
print()
print('=== Crashed thread triggerInfo / reason ===')
ft = crash['faultingThread']
thread = crash['threads'][ft]
for k,v in thread.items():
    if k != 'frames':
        print(f'  {k}: {v}')

# lastExceptionBacktrace NSException info
print()
print('=== NSException info (if available) ===')
for key in ['lastExceptionType', 'lastExceptionMessage', 'lastExceptionInfo']:
    if key in crash:
        print(f'  {key}: {crash[key]}')
